  1→import { useCallback, useEffect, useState } from "react";
  2→import { useWorkspaceState } from "../stores/workspace-state";
  3→
  4→// ---------------------------------------------------------------------------
  5→// Domain types mirroring backend SkillListItem / SkillDetailResponse
  6→// ---------------------------------------------------------------------------
  7→
  8→export type SkillStatus = "draft" | "active" | "deprecated";
  9→
 10→export type SkillSourceType = "github" | "git";
 11→
 12→export type SkillSource = {
 13→  type: SkillSourceType;
 14→  source: string;
 15→  ref?: string;
 16→  subpath?: string;
 17→  skills?: string[];
 18→};
 19→
 20→export type SkillListItem = {
 21→  id: string;
 22→  name: string;
 23→  description: string;
 24→  version: string;
 25→  status: SkillStatus;
 26→  source: SkillSource;
 27→  required_tools: Array<{ id: string; name: string }>;
 28→  agent_count: number;
 29→  created_at: string;
 30→};
 31→
 32→export type SkillDetailResponse = {
 33→  skill: SkillListItem & {
 34→    created_by?: string;
 35→    updated_at?: string;
 36→  };
 37→  required_tools: Array<{ id: string; name: string }>;
 38→  agents: Array<{ id: string; name: string }>;
 39→  governed_by: Array<{ id: string; name: string; status: string }>;
 40→};
 41→
 42→export type CreateSkillInput = {
 43→  name: string;
 44→  description: string;
 45→  version: string;
 46→  source: SkillSource;
 47→  required_tool_ids?: string[];
 48→};
 49→
 50→// ---------------------------------------------------------------------------
 51→// URL builders
 52→// ---------------------------------------------------------------------------
 53→
 54→export function buildSkillsUrl(workspaceId: string, status?: SkillStatus): string {
 55→  const base = `/api/workspaces/${encodeURIComponent(workspaceId)}/skills`;
 56→  return status ? `${base}?status=${encodeURIComponent(status)}` : base;
 57→}
 58→
 59→export function buildSkillDetailUrl(workspaceId: string, skillId: string): string {
 60→  return `/api/workspaces/${encodeURIComponent(workspaceId)}/skills/${encodeURIComponent(skillId)}`;
 61→}
 62→
 63→export function buildSkillActivateUrl(workspaceId: string, skillId: string): string {
 64→  return `/api/workspaces/${encodeURIComponent(workspaceId)}/skills/${encodeURIComponent(skillId)}/activate`;
 65→}
 66→
 67→export function buildSkillDeprecateUrl(workspaceId: string, skillId: string): string {
 68→  return `/api/workspaces/${encodeURIComponent(workspaceId)}/skills/${encodeURIComponent(skillId)}/deprecate`;
 69→}
 70→
 71→// ---------------------------------------------------------------------------
 72→// useSkills — list skills with optional status filter
 73→// ---------------------------------------------------------------------------
 74→
 75→type UseSkillsReturn = {
 76→  skills: SkillListItem[];
 77→  isLoading: boolean;
 78→  error?: string;
 79→  refresh: () => void;
 80→};
 81→
 82→export function useSkills(statusFilter?: SkillStatus): UseSkillsReturn {
 83→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
 84→  const [skills, setSkills] = useState<SkillListItem[]>([]);
 85→  const [isLoading, setIsLoading] = useState(false);
 86→  const [error, setError] = useState<string | undefined>();
 87→
 88→  const fetchSkills = useCallback(async () => {
 89→    if (!workspaceId) return;
 90→
 91→    setIsLoading(true);
 92→    setError(undefined);
 93→
 94→    try {
 95→      const url = buildSkillsUrl(workspaceId, statusFilter);
 96→      const response = await fetch(url);
 97→      if (!response.ok) {
 98→        const body = await response.text();
 99→        throw new Error(body);
100→      }
101→      const data = (await response.json()) as { skills: SkillListItem[] };
102→      setSkills(data.skills);
103→    } catch (err) {
104→      setError(err instanceof Error ? err.message : "Failed to load skills");
105→    } finally {
106→      setIsLoading(false);
107→    }
108→  }, [workspaceId, statusFilter]);
