 48→function updateField<K extends keyof ConfigStepState>(
 49→  state: ConfigStepState,
 50→  field: K,
 51→  value: ConfigStepState[K],
 52→): ConfigStepState {
 53→  return { ...state, [field]: value };
 54→}
 55→
 56→function updateSandboxField(
 57→  state: ConfigStepState,
 58→  field: keyof SandboxConfigState,
 59→  value: string,
 60→): ConfigStepState {
