100→                  className="accent-primary"
101→                />
102→                <span className="text-sm font-medium">{title}</span>
103→              </div>
104→              <span className="pl-5 text-xs text-muted-foreground">{desc}</span>
105→            </label>
106→          ))}
107→        </div>
108→      </fieldset>
109→
