132→          placeholder="What does this agent do?"
133→          rows={2}
134→        />
135→      </div>
136→
137→      {/* Model */}
138→      <div className="flex flex-col gap-1.5">
139→        <Label htmlFor="agent-model">Model (optional)</Label>
140→        <Input
141→          id="agent-model"
142→          value={state.model}
143→          onChange={(e) => onChange(updateField(state, "model", e.target.value))}
144→          placeholder="e.g. claude-sonnet-4-20250514"
145→        />
146→      </div>
147→
148→      {/* Sandbox config (conditional) */}
149→      {state.runtime === "sandbox" ? (
150→        <fieldset className="flex flex-col gap-3 rounded-lg border border-border p-4">
151→          <legend className="px-1 text-xs font-medium text-muted-foreground">Sandbox Configuration</legend>
152→          <div className="flex flex-col gap-1.5">
153→            <Label htmlFor="sandbox-image">Image (optional)</Label>
154→            <Input
155→              id="sandbox-image"
156→              value={state.sandboxConfig.image}
157→              onChange={(e) => onChange(updateSandboxField(state, "image", e.target.value))}
158→              placeholder="e.g. node:20-slim"
