    stubFetch({
      "check-name": () =>
        new Response(JSON.stringify({ available: true }), {
          status: 200,
          headers: { "Content-Type": "application/json" },
        }),
      "/agents": (_url, init) => {
        if (init?.method === "POST") {
          return new Response(
            JSON.stringify({
              agent: {
                id: "new-agent-1",
                name: "My Agent",
                runtime: "sandbox",
                identity_id: "id-new",
                created_at: "2026-03-28T00:00:00Z",
